    if (l === "is_vip") o[k] = "y";
    else if (l === "is_buy" || l === "is_buy_whole" || l === "can_vip_watch" || l === "has_buy") o[k] = true;
    else if (l === "type" && (v === "vip" || v === "coin" || v === "points" || v === "money")) o[k] = "free";
    else if (l === "pay_type" && v && v !== "free") o[k] = "free";
    else if (l === "methods" && Array.isArray(v)) o[k] = [];
    else if (l === "vip_episodes" || l === "coin_episodes" || l === "points_episodes") o[k] = [];
    else if ((l === "price" || l === "money" || l === "episode_price" || l === "points_price") && v !== "") o[k] = 0;
